import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.SKJoNiAS.js";const p=JSON.parse('{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),d={name:"guide/introduction.md"};function l(i,t,n,c,s,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h1><p>AKFun 是一个基于 <strong>Webpack</strong> 与 <strong>Rollup</strong> 的多场景前端打包工具，支持 Vue、React、React + TypeScript 技术栈，致力于提供&quot;零配置、开箱即用&quot;的前端工程能力，让开发者专注于业务开发。</p><h2 id="主要特性" tabindex="-1">主要特性 <a class="header-anchor" href="#主要特性" aria-label="Permalink to &quot;主要特性&quot;">​</a></h2><ul><li><strong>零配置</strong> — 内置前端工程最佳实践的默认配置，安装后即可使用，无需繁琐的初始化步骤。</li><li><strong>多技术栈支持</strong> — 同时支持 Vue、React、React + TypeScript 的本地调试与生产构建。</li><li><strong>多种构建模式</strong> — 涵盖本地开发（含热更新 / 接口代理）、生产构建、UMD 库构建、ESM 库构建、Node 模块构建等场景。</li><li><strong>灵活可配</strong> — 支持自定义入口、路径别名、接口代理、公共样式注入、ESLint / StyleLint、Babel / Loader / Plugin 扩展等配置项。</li><li><strong>样式与规范集成</strong> — 内置 Autoprefixer、Sass、PostCSS、ESLint、StyleLint，帮助团队统一代码风格。</li><li><strong>环境变量替换</strong> — 基于 <a href="https://www.npmjs.com/package/params-replace-loader" target="_blank" rel="noreferrer">params-replace-loader</a> 实现多环境参数批量替换。</li><li><strong>项目模板</strong> — 提供完整的 Vue / React 项目模板，一键创建新项目。</li><li><strong>内置缓存机制</strong> — 利用缓存加速二次构建，提升开发效率。</li></ul><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><p>AKFun 在不同构建场景下使用不同的底层工具：</p><table tabindex="0"><thead><tr><th>构建场景</th><th>底层工具</th><th>说明</th></tr></thead><tbody><tr><td>本地开发 (<code>dev</code>)</td><td>Webpack</td><td>提供 DevServer、热更新、接口代理等能力</td></tr><tr><td>生产构建 (<code>build</code>)</td><td>Webpack</td><td>代码压缩、分包优化、Source Map 等</td></tr><tr><td>UMD 库构建 (<code>build2lib</code>)</td><td>Webpack</td><td>输出 UMD 格式，可通过 <code>&lt;script&gt;</code> 标签引入</td></tr><tr><td>ESM 库构建 (<code>build2esm</code>)</td><td>Rollup</td><td>输出 ESM 格式，适用于现代模块系统</td></tr><tr><td>Node 模块构建 (<code>build2node</code>)</td><td>Rollup</td><td>输出 Node 模块，适用于 CLI 工具等场景</td></tr></tbody></table><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>需要快速启动一个 Vue / React 项目，不想花时间配置 Webpack</li><li>团队需要统一的前端工程化方案</li><li>需要将组件或工具库打包为 UMD / ESM 格式发布到 npm</li><li>需要构建 Node CLI 工具</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/akfun/html/guide/installation.html">安装 AKFun</a> — 了解如何安装</li><li><a href="/akfun/html/guide/quick-start.html">快速开始</a> — 5 分钟上手</li><li><a href="/akfun/html/guide/commands.html">命令说明</a> — 查看所有可用命令</li></ul>',11)])])}const g=e(d,[["render",l]]);export{p as __pageData,g as default};
